  <text x="20" y="30" fill="#fafafa" font-size="16" font-weight="700" font-family="sans-serif">ビットコイン vs ソフトウェア株(IGV) — 第2四半期デカップリング</text>
  <rect x="460" y="50" width="14" height="14" fill="#f59e0b"/>
  <text x="478" y="61" fill="#e4e4e7" font-family="sans-serif" font-size="13">ビットコイン(第2四半期 -14.09%)</text>
  <rect x="460" y="70" width="14" height="14" fill="#60a5fa"/>
  <text x="478" y="81" fill="#e4e4e7" font-family="sans-serif" font-size="13">IGV(同期間 +12%)</text>
